SELECT 
FROM ai_operation_tasks

    del_flag = '0'
    AND site_id = #{siteId}
    AND task_type = #{taskType}
    AND task_name LIKE CONCAT('%', #{taskName}, '%')
    AND trigger_type = #{triggerType}
    AND status = #{status}

ORDER BY priority DESC, id DESC

mapper.update:
UPDATE ai_operation_tasks
site_id = #{siteId}, task_type = #{taskType}, task_name = #{taskName}, trigger_type = #{triggerType}, cron_expr = #{cronExpr}, params = #{taskParams}::jsonb, priority = #{priority}, status = #{status}, last_run_at = #{lastRunAt}, next_run_at = #{nextRunAt}, last_result = #{lastResult}, retry_count = #{retryCount}, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}
